	private LibrettoProjectProfileGrammarAccess grammarAccess;

	@Override
	protected InternalLibrettoProjectProfileParser createParser() {
		InternalLibrettoProjectProfileParser result = new InternalLibrettoProjectProfileParser(null);
		result.setGrammarAccess(grammarAccess);
		return result;
	}

	@Override
	protected String getRuleName(AbstractElement element) {
		return nameMappings.getRuleName(element);
	}

	@Override
	protected String[] getInitialHiddenTokens() {
		return new String[] { "RULE_WS", "RULE_ML_COMMENT", "RULE_SL_COMMENT" };
	}

	public LibrettoProjectProfileGrammarAccess getGrammarAccess() {
		return this.grammarAccess;
	}

